import React, { useState } from "react";
import { auth } from "../firebase";
import { signInWithEmailAndPassword, sendPasswordResetEmail } from "firebase/auth";
import { useNavigate, Link } from "react-router-dom";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [message, setMessage] = useState("");
  const [resetSent, setResetSent] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      await signInWithEmailAndPassword(auth, email, password);
      setMessage("Login successful!");
      navigate("/");
    } catch (error) {
      console.error("Login error:", error);
      setMessage("Invalid email or password. Try again.");
    }
  };

  const handleResetPassword = async () => {
    if (!email) {
      setMessage("Enter your email to reset password.");
      return;
    }
    try {
      await sendPasswordResetEmail(auth, email);
      setResetSent(true);
      setMessage("Password reset link sent! Check your email.");
    } catch (error) {
      console.error("Reset error:", error);
      setMessage("Error sending reset email. Please try again.");
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-black via-gray-900 to-purple-950">
      <div className="bg-gray-950 p-8 rounded-2xl shadow-lg w-full max-w-md border border-gray-800">
        <h2 className="text-2xl font-bold text-center text-white mb-6">
          Sign in to <span className="text-purple-500">Godemar’s Empire</span>
        </h2>

        {message && (
          <div className="mb-4 text-sm text-center text-purple-400">{message}</div>
        )}

        <form onSubmit={handleLogin} className="space-y-5">
          <div>
            <label className="block text-gray-300 text-sm mb-1">Email</label>
            <input
              type="email"
              placeholder="Enter your email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:ring-2 focus:ring-purple-600 focus:outline-none"
              required
            />
          </div>

          <div>
            <label className="block text-gray-300 text-sm mb-1">Password</label>
            <div className="relative">
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full px-4 py-2 bg-gray-900 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:ring-2 focus:ring-purple-600 focus:outline-none"
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-2 text-gray-400 hover:text-purple-400 text-sm"
              >
                {showPassword ? "Hide" : "Show"}
              </button>
            </div>
          </div>

          <div className="flex justify-between items-center text-sm mt-1">
            <button
              type="button"
              onClick={handleResetPassword}
              className="text-purple-500 hover:underline"
            >
              Forgot Password?
            </button>
            <Link to="/signup" className="text-gray-400 hover:text-purple-500">
              Create account
            </Link>
          </div>

          <button
            type="submit"
            className="w-full mt-4 bg-purple-600 hover:bg-purple-700 text-white py-2 rounded-lg font-semibold transition-all duration-300"
          >
            Sign In
          </button>
        </form>

        {resetSent && (
          <p className="text-xs text-center text-green-400 mt-4">
            Please check your inbox for the reset link.
          </p>
        )}
      </div>
    </div>
  );
}
